mapper.select:
SELECT id, batch_code, batch_name, source_type, source_name, rule_action, default_priority, active, total_rule_count, active_rule_count, memo, created_by, updated_by, created_at, updated_at FROM admin_ip_block_batch
AND active = #{active}
AND (batch_code LIKE CONCAT('%', #{keyword}, '%') OR batch_name LIKE CONCAT('%', #{keyword}, '%') OR source_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY created_at DESC, id DESC LIMIT #{limit}

mapper.update:
UPDATE admin_ip_block_batch
   SET total_rule_count = #{total}, active_rule_count = #{active}, updated_by = #{updatedBy}
 WHERE id = #{batchId}

UPDATE admin_ip_block_batch
   SET active = #{active}, updated_by = #{updatedBy}
 WHERE id = #{id}

UPDATE admin_security_block_rule
   SET active = #{active}
 WHERE batch_id = #{batchId}
   AND control_mode <> 'MANUAL_OVERRIDE'
